content.problemStatement:
What will be the output of the following C++ program?

```cpp
#include 
using namespace std;

// Function to calculate and print the sum of two numbers
void addNumbers(int a, int b) {
    int sum = a + b;
    cout << "The sum of " << a << " and " << b << " is: " << sum << endl;
}

int main() {
    // Print statement before the function call
    cout << "Starting the addition..." << endl;

    // Call the addNumbers function with direct values
    addNumbers(5, 8);

    // Print statement after the function call
    cout << "Addition complete." << endl;

    return 0;
}

```

